import { Table, Thead, Tr, Th, Tbody, Td } from '@chakra-ui/react';
import React, {useState, useEffect } from 'react';
import Axios from 'axios';

  const Application = (props) => {

  const [data, setData] = useState([]);
  const { etablissement } = useParams();


    useEffect(() => {
      const etablissement = props.match.params.etablissement;
      Axios.get('http://localhost:3001/api/utilisateur/${etablissement}').then(res =>  
        setData(res.data))
    }, [])

  const Obtenir_element_nom = () => {
    return data.map(donnee => {
      return (
       <Tr>
        <Td>{donnee.id}</Td>
        <Td>{donnee.etablissement_type}</Td>
        <Td>{donnee.etablissement}</Td>
        <Td>{donnee.location}</Td>
        <Td>{donnee.address}</Td>
        <Td>{donnee.mail}</Td>
       </Tr>
      )
     })
     }

  return (
  <div>
   <Table>
    <Thead>
     <Tr>
      <Th>id</Th>
      <Th>etablissement_type</Th>
      <Th>etablissement</Th>
      <Th>location</Th>
      <Th>address</Th>
      <Th>mail</Th>
     </Tr>
    </Thead>

   <Tbody>{Obtenir_element_nom()}</Tbody>
  </Table>
 </div>
  );
}

export default Application;
